A simple queue layout storing game commands to execute sequentially on tick:

```cpp
#include <queue>
#include <string>

struct FGameCommand {
    std::string Action;
};

class UCommandProcessor {
private:
    std::queue<FGameCommand> CommandQueue;

public:
    void EnqueueCommand(FGameCommand Cmd) {
        CommandQueue.push(Cmd);
    }

    void ProcessCommands() {
        while (!CommandQueue.empty()) {
            FGameCommand ActiveCmd = CommandQueue.front();
            Execute(ActiveCmd.Action);
            CommandQueue.pop(); // Remove processed command
        }
    }

private:
    void Execute(std::string Action) {}
};
```
